// Format chat history into transcript JSONB
const chatHistory = $input.all();
const initData = $('Init Battle').item.json;

// Determine outcome from Set Outcome nodes (only one will have executed)
let outcome = 'timeout';
try {
  outcome = $('Set Outcome Timeout').first().json.outcome || 'timeout';
} catch (e) {
  try {
    outcome = $('Set Outcome Success Agent').first().json.outcome || 'success';
  } catch (e2) {
    try {
      outcome = $('Set Outcome Success Persona').first().json.outcome || 'success';
    } catch (e3) {
      // Default to timeout if no Set Outcome node found
      outcome = 'timeout';
    }
  }
}

const messages = chatHistory.map((row, index) => {
  const msg = row.json.message;
  return {
    role: msg.type === 'ai' ? 'assistant' : 'user',
    content: msg.content,
    sequence: index + 1,
    tool_calls: msg.tool_calls?.length > 0 ? msg.tool_calls : undefined
  };
});

const turnCount = Math.floor(messages.length / 2);
const startTime = new Date(initData.start_time);
const duration = Math.floor((Date.now() - startTime.getTime()) / 1000);

return {
  json: {
    test_run_id: initData.test_run_id,
    persona_id: initData.persona_id,
    outcome: outcome,
    turns: turnCount,
    duration_seconds: duration,
    transcript: { messages },
    session_id: initData.session_id
  }
};

